# Hidden period is 11 (binary) = 3 (decimal)
hidden_period = 3

# Group counts by input (first 2 bits) and output (last 2 bits)
input_outputs = {}
for bitstring, count in counts.items():
    if count > 0:
        input_bits = int(bitstring[:2], 2)  # First 2 bits as input
        output_bits = bitstring[2:]  # Last 2 bits as output
        if input_bits not in input_outputs:
            input_outputs[input_bits] = output_bits
        else:
            assert input_outputs[input_bits] == output_bits, f"Input {input_bits} has inconsistent outputs"

# Verify periodic property: f(x) = f(x ⊕ period)
for input_val in input_outputs:
    paired_input = input_val ^ hidden_period
    if paired_input in input_outputs:
        assert input_outputs[input_val] == input_outputs[paired_input], \
            f"Periodic property violated: f({input_val}) ≠ f({paired_input})"
